function out = HastyV2_syms
out{1} = @init;
out{2} = @fun_eval;
out{3} = @jacobian;
out{4} = @jacobianp;
out{5} = @hessians;
out{6} = @hessiansp;
out{7} = @der3;
out{8} = @der4;
out{9} = @der5;

% --------------------------------------------------------------------------
function dydt = fun_eval(t,kmrgd,par_s,par_a,par_f,par_g,par_T)
dydt=[(1+kmrgd(1)^2+par_a*par_s*kmrgd(1)^4)/((1+kmrgd(1)^2+par_s*kmrgd(1)^4)*(1+kmrgd(2)^4))-par_f*kmrgd(1);
((1+kmrgd(1)^2+par_a*par_s*kmrgd(1)^4)/((1+kmrgd(1)^2+par_s*kmrgd(1)^4)*(1+kmrgd(2)^4))-par_g*kmrgd(2))/par_T;];

% --------------------------------------------------------------------------
function [tspan,y0,options] = init
handles = feval(HastyV2_syms);
y0=[0,0];
options = odeset('Jacobian',handles(3),'JacobianP',handles(4),'Hessians',handles(5),'HessiansP',handles(6));
tspan = [0 10];

% --------------------------------------------------------------------------
function jac = jacobian(t,kmrgd,par_s,par_a,par_f,par_g,par_T)
jac=[ (2*kmrgd(1) + 4*kmrgd(1)^3*par_a*par_s)/((kmrgd(2)^4 + 1)*(kmrgd(1)^4*par_s + kmrgd(1)^2 + 1)) - par_f - ((2*kmrgd(1) + 4*kmrgd(1)^3*par_s)*(kmrgd(1)^2 + kmrgd(1)^4*par_a*par_s + 1))/((kmrgd(2)^4 + 1)*(kmrgd(1)^4*par_s + kmrgd(1)^2 + 1)^2) , -(4*kmrgd(2)^3*(kmrgd(1)^2 + kmrgd(1)^4*par_a*par_s + 1))/((kmrgd(2)^4 + 1)^2*(kmrgd(1)^4*par_s + kmrgd(1)^2 + 1)) ; ((2*kmrgd(1) + 4*kmrgd(1)^3*par_a*par_s)/((kmrgd(2)^4 + 1)*(kmrgd(1)^4*par_s + kmrgd(1)^2 + 1)) - ((2*kmrgd(1) + 4*kmrgd(1)^3*par_s)*(kmrgd(1)^2 + kmrgd(1)^4*par_a*par_s + 1))/((kmrgd(2)^4 + 1)*(kmrgd(1)^4*par_s + kmrgd(1)^2 + 1)^2))/par_T , -(par_g + (4*kmrgd(2)^3*(kmrgd(1)^2 + kmrgd(1)^4*par_a*par_s + 1))/((kmrgd(2)^4 + 1)^2*(kmrgd(1)^4*par_s + kmrgd(1)^2 + 1)))/par_T ];
% --------------------------------------------------------------------------
function jacp = jacobianp(t,kmrgd,par_s,par_a,par_f,par_g,par_T)
jacp=[ (kmrgd(1)^4*par_a)/((kmrgd(2)^4 + 1)*(kmrgd(1)^4*par_s + kmrgd(1)^2 + 1)) - (kmrgd(1)^4*(kmrgd(1)^2 + kmrgd(1)^4*par_a*par_s + 1))/((kmrgd(2)^4 + 1)*(kmrgd(1)^4*par_s + kmrgd(1)^2 + 1)^2) , (kmrgd(1)^4*par_s)/((kmrgd(2)^4 + 1)*(kmrgd(1)^4*par_s + kmrgd(1)^2 + 1)) , -kmrgd(1) , 0 , 0 ; ((kmrgd(1)^4*par_a)/((kmrgd(2)^4 + 1)*(kmrgd(1)^4*par_s + kmrgd(1)^2 + 1)) - (kmrgd(1)^4*(kmrgd(1)^2 + kmrgd(1)^4*par_a*par_s + 1))/((kmrgd(2)^4 + 1)*(kmrgd(1)^4*par_s + kmrgd(1)^2 + 1)^2))/par_T , (kmrgd(1)^4*par_s)/(par_T*(kmrgd(2)^4 + 1)*(kmrgd(1)^4*par_s + kmrgd(1)^2 + 1)) , 0 , -kmrgd(2)/par_T , (kmrgd(2)*par_g - (kmrgd(1)^2 + kmrgd(1)^4*par_a*par_s + 1)/((kmrgd(2)^4 + 1)*(kmrgd(1)^4*par_s + kmrgd(1)^2 + 1)))/par_T^2 ];
% --------------------------------------------------------------------------
function hess = hessians(t,kmrgd,par_s,par_a,par_f,par_g,par_T)
hess1=[ (12*kmrgd(1)^2*par_a*par_s + 2)/((kmrgd(2)^4 + 1)*(kmrgd(1)^4*par_s + kmrgd(1)^2 + 1)) - ((12*kmrgd(1)^2*par_s + 2)*(kmrgd(1)^2 + kmrgd(1)^4*par_a*par_s + 1))/((kmrgd(2)^4 + 1)*(kmrgd(1)^4*par_s + kmrgd(1)^2 + 1)^2) + (2*(2*kmrgd(1) + 4*kmrgd(1)^3*par_s)^2*(kmrgd(1)^2 + kmrgd(1)^4*par_a*par_s + 1))/((kmrgd(2)^4 + 1)*(kmrgd(1)^4*par_s + kmrgd(1)^2 + 1)^3) - (2*(2*kmrgd(1) + 4*kmrgd(1)^3*par_a*par_s)*(2*kmrgd(1) + 4*kmrgd(1)^3*par_s))/((kmrgd(2)^4 + 1)*(kmrgd(1)^4*par_s + kmrgd(1)^2 + 1)^2) , (4*kmrgd(2)^3*(2*kmrgd(1) + 4*kmrgd(1)^3*par_s)*(kmrgd(1)^2 + kmrgd(1)^4*par_a*par_s + 1))/((kmrgd(2)^4 + 1)^2*(kmrgd(1)^4*par_s + kmrgd(1)^2 + 1)^2) - (4*kmrgd(2)^3*(2*kmrgd(1) + 4*kmrgd(1)^3*par_a*par_s))/((kmrgd(2)^4 + 1)^2*(kmrgd(1)^4*par_s + kmrgd(1)^2 + 1)) ; ((12*kmrgd(1)^2*par_a*par_s + 2)/((kmrgd(2)^4 + 1)*(kmrgd(1)^4*par_s + kmrgd(1)^2 + 1)) - ((12*kmrgd(1)^2*par_s + 2)*(kmrgd(1)^2 + kmrgd(1)^4*par_a*par_s + 1))/((kmrgd(2)^4 + 1)*(kmrgd(1)^4*par_s + kmrgd(1)^2 + 1)^2) + (2*(2*kmrgd(1) + 4*kmrgd(1)^3*par_s)^2*(kmrgd(1)^2 + kmrgd(1)^4*par_a*par_s + 1))/((kmrgd(2)^4 + 1)*(kmrgd(1)^4*par_s + kmrgd(1)^2 + 1)^3) - (2*(2*kmrgd(1) + 4*kmrgd(1)^3*par_a*par_s)*(2*kmrgd(1) + 4*kmrgd(1)^3*par_s))/((kmrgd(2)^4 + 1)*(kmrgd(1)^4*par_s + kmrgd(1)^2 + 1)^2))/par_T , -((4*kmrgd(2)^3*(2*kmrgd(1) + 4*kmrgd(1)^3*par_a*par_s))/((kmrgd(2)^4 + 1)^2*(kmrgd(1)^4*par_s + kmrgd(1)^2 + 1)) - (4*kmrgd(2)^3*(2*kmrgd(1) + 4*kmrgd(1)^3*par_s)*(kmrgd(1)^2 + kmrgd(1)^4*par_a*par_s + 1))/((kmrgd(2)^4 + 1)^2*(kmrgd(1)^4*par_s + kmrgd(1)^2 + 1)^2))/par_T ];
hess2=[ (4*kmrgd(2)^3*(2*kmrgd(1) + 4*kmrgd(1)^3*par_s)*(kmrgd(1)^2 + kmrgd(1)^4*par_a*par_s + 1))/((kmrgd(2)^4 + 1)^2*(kmrgd(1)^4*par_s + kmrgd(1)^2 + 1)^2) - (4*kmrgd(2)^3*(2*kmrgd(1) + 4*kmrgd(1)^3*par_a*par_s))/((kmrgd(2)^4 + 1)^2*(kmrgd(1)^4*par_s + kmrgd(1)^2 + 1)) , (32*kmrgd(2)^6*(kmrgd(1)^2 + kmrgd(1)^4*par_a*par_s + 1))/((kmrgd(2)^4 + 1)^3*(kmrgd(1)^4*par_s + kmrgd(1)^2 + 1)) - (12*kmrgd(2)^2*(kmrgd(1)^2 + kmrgd(1)^4*par_a*par_s + 1))/((kmrgd(2)^4 + 1)^2*(kmrgd(1)^4*par_s + kmrgd(1)^2 + 1)) ; -((4*kmrgd(2)^3*(2*kmrgd(1) + 4*kmrgd(1)^3*par_a*par_s))/((kmrgd(2)^4 + 1)^2*(kmrgd(1)^4*par_s + kmrgd(1)^2 + 1)) - (4*kmrgd(2)^3*(2*kmrgd(1) + 4*kmrgd(1)^3*par_s)*(kmrgd(1)^2 + kmrgd(1)^4*par_a*par_s + 1))/((kmrgd(2)^4 + 1)^2*(kmrgd(1)^4*par_s + kmrgd(1)^2 + 1)^2))/par_T , -((12*kmrgd(2)^2*(kmrgd(1)^2 + kmrgd(1)^4*par_a*par_s + 1))/((kmrgd(2)^4 + 1)^2*(kmrgd(1)^4*par_s + kmrgd(1)^2 + 1)) - (32*kmrgd(2)^6*(kmrgd(1)^2 + kmrgd(1)^4*par_a*par_s + 1))/((kmrgd(2)^4 + 1)^3*(kmrgd(1)^4*par_s + kmrgd(1)^2 + 1)))/par_T ];
hess(:,:,1) =hess1;
hess(:,:,2) =hess2;
% --------------------------------------------------------------------------
function hessp = hessiansp(t,kmrgd,par_s,par_a,par_f,par_g,par_T)
hessp1=[ (4*kmrgd(1)^3*par_a)/((kmrgd(2)^4 + 1)*(kmrgd(1)^4*par_s + kmrgd(1)^2 + 1)) - (kmrgd(1)^4*(2*kmrgd(1) + 4*kmrgd(1)^3*par_a*par_s))/((kmrgd(2)^4 + 1)*(kmrgd(1)^4*par_s + kmrgd(1)^2 + 1)^2) - (4*kmrgd(1)^3*(kmrgd(1)^2 + kmrgd(1)^4*par_a*par_s + 1))/((kmrgd(2)^4 + 1)*(kmrgd(1)^4*par_s + kmrgd(1)^2 + 1)^2) + (2*kmrgd(1)^4*(2*kmrgd(1) + 4*kmrgd(1)^3*par_s)*(kmrgd(1)^2 + kmrgd(1)^4*par_a*par_s + 1))/((kmrgd(2)^4 + 1)*(kmrgd(1)^4*par_s + kmrgd(1)^2 + 1)^3) - (kmrgd(1)^4*par_a*(2*kmrgd(1) + 4*kmrgd(1)^3*par_s))/((kmrgd(2)^4 + 1)*(kmrgd(1)^4*par_s + kmrgd(1)^2 + 1)^2) , (4*kmrgd(1)^4*kmrgd(2)^3*(kmrgd(1)^2 + kmrgd(1)^4*par_a*par_s + 1))/((kmrgd(2)^4 + 1)^2*(kmrgd(1)^4*par_s + kmrgd(1)^2 + 1)^2) - (4*kmrgd(1)^4*kmrgd(2)^3*par_a)/((kmrgd(2)^4 + 1)^2*(kmrgd(1)^4*par_s + kmrgd(1)^2 + 1)) ; -((kmrgd(1)^4*(2*kmrgd(1) + 4*kmrgd(1)^3*par_a*par_s))/((kmrgd(2)^4 + 1)*(kmrgd(1)^4*par_s + kmrgd(1)^2 + 1)^2) - (4*kmrgd(1)^3*par_a)/((kmrgd(2)^4 + 1)*(kmrgd(1)^4*par_s + kmrgd(1)^2 + 1)) + (4*kmrgd(1)^3*(kmrgd(1)^2 + kmrgd(1)^4*par_a*par_s + 1))/((kmrgd(2)^4 + 1)*(kmrgd(1)^4*par_s + kmrgd(1)^2 + 1)^2) - (2*kmrgd(1)^4*(2*kmrgd(1) + 4*kmrgd(1)^3*par_s)*(kmrgd(1)^2 + kmrgd(1)^4*par_a*par_s + 1))/((kmrgd(2)^4 + 1)*(kmrgd(1)^4*par_s + kmrgd(1)^2 + 1)^3) + (kmrgd(1)^4*par_a*(2*kmrgd(1) + 4*kmrgd(1)^3*par_s))/((kmrgd(2)^4 + 1)*(kmrgd(1)^4*par_s + kmrgd(1)^2 + 1)^2))/par_T , ((4*kmrgd(1)^4*kmrgd(2)^3*(kmrgd(1)^2 + kmrgd(1)^4*par_a*par_s + 1))/((kmrgd(2)^4 + 1)^2*(kmrgd(1)^4*par_s + kmrgd(1)^2 + 1)^2) - (4*kmrgd(1)^4*kmrgd(2)^3*par_a)/((kmrgd(2)^4 + 1)^2*(kmrgd(1)^4*par_s + kmrgd(1)^2 + 1)))/par_T ];
hessp2=[ (4*kmrgd(1)^3*par_s)/((kmrgd(2)^4 + 1)*(kmrgd(1)^4*par_s + kmrgd(1)^2 + 1)) - (kmrgd(1)^4*par_s*(2*kmrgd(1) + 4*kmrgd(1)^3*par_s))/((kmrgd(2)^4 + 1)*(kmrgd(1)^4*par_s + kmrgd(1)^2 + 1)^2) , -(4*kmrgd(1)^4*kmrgd(2)^3*par_s)/((kmrgd(2)^4 + 1)^2*(kmrgd(1)^4*par_s + kmrgd(1)^2 + 1)) ; ((4*kmrgd(1)^3*par_s)/((kmrgd(2)^4 + 1)*(kmrgd(1)^4*par_s + kmrgd(1)^2 + 1)) - (kmrgd(1)^4*par_s*(2*kmrgd(1) + 4*kmrgd(1)^3*par_s))/((kmrgd(2)^4 + 1)*(kmrgd(1)^4*par_s + kmrgd(1)^2 + 1)^2))/par_T , -(4*kmrgd(1)^4*kmrgd(2)^3*par_s)/(par_T*(kmrgd(2)^4 + 1)^2*(kmrgd(1)^4*par_s + kmrgd(1)^2 + 1)) ];
hessp3=[ -1 , 0 ; 0 , 0 ];
hessp4=[ 0 , 0 ; 0 , -1/par_T ];
hessp5=[ 0 , 0 ; -((2*kmrgd(1) + 4*kmrgd(1)^3*par_a*par_s)/((kmrgd(2)^4 + 1)*(kmrgd(1)^4*par_s + kmrgd(1)^2 + 1)) - ((2*kmrgd(1) + 4*kmrgd(1)^3*par_s)*(kmrgd(1)^2 + kmrgd(1)^4*par_a*par_s + 1))/((kmrgd(2)^4 + 1)*(kmrgd(1)^4*par_s + kmrgd(1)^2 + 1)^2))/par_T^2 , (par_g + (4*kmrgd(2)^3*(kmrgd(1)^2 + kmrgd(1)^4*par_a*par_s + 1))/((kmrgd(2)^4 + 1)^2*(kmrgd(1)^4*par_s + kmrgd(1)^2 + 1)))/par_T^2 ];
hessp(:,:,1) =hessp1;
hessp(:,:,2) =hessp2;
hessp(:,:,3) =hessp3;
hessp(:,:,4) =hessp4;
hessp(:,:,5) =hessp5;
