function tens3  = der3(t,kmrgd,par_s,par_a,par_f,par_g,par_T)
tens31=[ (6*(2*kmrgd(1) + 4*kmrgd(1)^3*par_a*par_s)*(2*kmrgd(1) + 4*kmrgd(1)^3*par_s)^2)/((kmrgd(2)^4 + 1)*(kmrgd(1)^4*par_s + kmrgd(1)^2 + 1)^3) - (3*(12*kmrgd(1)^2*par_a*par_s + 2)*(2*kmrgd(1) + 4*kmrgd(1)^3*par_s))/((kmrgd(2)^4 + 1)*(kmrgd(1)^4*par_s + kmrgd(1)^2 + 1)^2) - (3*(2*kmrgd(1) + 4*kmrgd(1)^3*par_a*par_s)*(12*kmrgd(1)^2*par_s + 2))/((kmrgd(2)^4 + 1)*(kmrgd(1)^4*par_s + kmrgd(1)^2 + 1)^2) - (6*(2*kmrgd(1) + 4*kmrgd(1)^3*par_s)^3*(kmrgd(1)^2 + kmrgd(1)^4*par_a*par_s + 1))/((kmrgd(2)^4 + 1)*(kmrgd(1)^4*par_s + kmrgd(1)^2 + 1)^4) + (24*kmrgd(1)*par_a*par_s)/((kmrgd(2)^4 + 1)*(kmrgd(1)^4*par_s + kmrgd(1)^2 + 1)) + (6*(2*kmrgd(1) + 4*kmrgd(1)^3*par_s)*(12*kmrgd(1)^2*par_s + 2)*(kmrgd(1)^2 + kmrgd(1)^4*par_a*par_s + 1))/((kmrgd(2)^4 + 1)*(kmrgd(1)^4*par_s + kmrgd(1)^2 + 1)^3) - (24*kmrgd(1)*par_s*(kmrgd(1)^2 + kmrgd(1)^4*par_a*par_s + 1))/((kmrgd(2)^4 + 1)*(kmrgd(1)^4*par_s + kmrgd(1)^2 + 1)^2) , (8*kmrgd(2)^3*(2*kmrgd(1) + 4*kmrgd(1)^3*par_a*par_s)*(2*kmrgd(1) + 4*kmrgd(1)^3*par_s))/((kmrgd(2)^4 + 1)^2*(kmrgd(1)^4*par_s + kmrgd(1)^2 + 1)^2) - (4*kmrgd(2)^3*(12*kmrgd(1)^2*par_a*par_s + 2))/((kmrgd(2)^4 + 1)^2*(kmrgd(1)^4*par_s + kmrgd(1)^2 + 1)) + (4*kmrgd(2)^3*(12*kmrgd(1)^2*par_s + 2)*(kmrgd(1)^2 + kmrgd(1)^4*par_a*par_s + 1))/((kmrgd(2)^4 + 1)^2*(kmrgd(1)^4*par_s + kmrgd(1)^2 + 1)^2) - (8*kmrgd(2)^3*(2*kmrgd(1) + 4*kmrgd(1)^3*par_s)^2*(kmrgd(1)^2 + kmrgd(1)^4*par_a*par_s + 1))/((kmrgd(2)^4 + 1)^2*(kmrgd(1)^4*par_s + kmrgd(1)^2 + 1)^3) ; -((3*(2*kmrgd(1) + 4*kmrgd(1)^3*par_a*par_s)*(12*kmrgd(1)^2*par_s + 2))/((kmrgd(2)^4 + 1)*(kmrgd(1)^4*par_s + kmrgd(1)^2 + 1)^2) + (3*(12*kmrgd(1)^2*par_a*par_s + 2)*(2*kmrgd(1) + 4*kmrgd(1)^3*par_s))/((kmrgd(2)^4 + 1)*(kmrgd(1)^4*par_s + kmrgd(1)^2 + 1)^2) - (6*(2*kmrgd(1) + 4*kmrgd(1)^3*par_a*par_s)*(2*kmrgd(1) + 4*kmrgd(1)^3*par_s)^2)/((kmrgd(2)^4 + 1)*(kmrgd(1)^4*par_s + kmrgd(1)^2 + 1)^3) + (6*(2*kmrgd(1) + 4*kmrgd(1)^3*par_s)^3*(kmrgd(1)^2 + kmrgd(1)^4*par_a*par_s + 1))/((kmrgd(2)^4 + 1)*(kmrgd(1)^4*par_s + kmrgd(1)^2 + 1)^4) - (24*kmrgd(1)*par_a*par_s)/((kmrgd(2)^4 + 1)*(kmrgd(1)^4*par_s + kmrgd(1)^2 + 1)) - (6*(2*kmrgd(1) + 4*kmrgd(1)^3*par_s)*(12*kmrgd(1)^2*par_s + 2)*(kmrgd(1)^2 + kmrgd(1)^4*par_a*par_s + 1))/((kmrgd(2)^4 + 1)*(kmrgd(1)^4*par_s + kmrgd(1)^2 + 1)^3) + (24*kmrgd(1)*par_s*(kmrgd(1)^2 + kmrgd(1)^4*par_a*par_s + 1))/((kmrgd(2)^4 + 1)*(kmrgd(1)^4*par_s + kmrgd(1)^2 + 1)^2))/par_T , -((4*kmrgd(2)^3*(12*kmrgd(1)^2*par_a*par_s + 2))/((kmrgd(2)^4 + 1)^2*(kmrgd(1)^4*par_s + kmrgd(1)^2 + 1)) - (8*kmrgd(2)^3*(2*kmrgd(1) + 4*kmrgd(1)^3*par_a*par_s)*(2*kmrgd(1) + 4*kmrgd(1)^3*par_s))/((kmrgd(2)^4 + 1)^2*(kmrgd(1)^4*par_s + kmrgd(1)^2 + 1)^2) - (4*kmrgd(2)^3*(12*kmrgd(1)^2*par_s + 2)*(kmrgd(1)^2 + kmrgd(1)^4*par_a*par_s + 1))/((kmrgd(2)^4 + 1)^2*(kmrgd(1)^4*par_s + kmrgd(1)^2 + 1)^2) + (8*kmrgd(2)^3*(2*kmrgd(1) + 4*kmrgd(1)^3*par_s)^2*(kmrgd(1)^2 + kmrgd(1)^4*par_a*par_s + 1))/((kmrgd(2)^4 + 1)^2*(kmrgd(1)^4*par_s + kmrgd(1)^2 + 1)^3))/par_T ];
